import json

def upgrade_dataset_structure(input_path, output_path):
    with open(input_path, 'r', encoding='utf-8') as f:
        data = json.load(f)

    upgraded_data = []

    for entry in data:
        messages = entry.get("messages", [])
        new_messages = []

        for msg in messages:
            if msg["role"] == "user":
                # Keep the user prompt as is
                new_messages.append(msg)
                user_content = msg["content"]
            
            elif msg["role"] == "assistant":
                try:
                    # Parse the existing JSON content
                    original_json = json.loads(msg["content"])
                    files = original_json.get("files", [])
                    
                    # 1. Generate Manifest (Detail Preservation)
                    manifest = [f["path"] for f in files]
                    
                    # 2. Generate a Logic Plan (Contextual anchor)
                    # We derive this from the user prompt to keep it relevant
                    plan = f"Architecting a solution for: '{user_content[:50]}...'. " \
                           f"Ensuring modularity across {len(manifest)} files using FastAPI and standard UI components."

                    # 3. Reconstruct into the Improved Schema
                    # No code is removed; 'files' remains identical to original
                    improved_structure = {
                        "plan": plan,
                        "manifest": manifest,
                        "files": files
                    }

                    new_messages.append({
                        "role": "assistant",
                        "content": json.dumps(improved_structure)
                    })
                except json.JSONDecodeError:
                    # If content isn't JSON, keep as is to avoid data loss
                    new_messages.append(msg)

        upgraded_data.append({"messages": new_messages})

    with open(output_path, 'w', encoding='utf-8') as f:
        json.dump(upgraded_data, f, indent=2)
    
    print(f"Successfully upgraded {len(upgraded_data)} examples to Manifest-First structure.")

# Usage
upgrade_dataset_structure("finetune_dataset.json", "Code-finetuning-dataset.json")